dtsPropsFor.TransferCheque:
/** "form" = editable inputs; "review"/"success" = read-only (success stamps "Cleared"). */
mode: "form" | "review" | "success";
/** Cheque serial number (shown top-right and in the MICR line). */
chequeNumber: string;
/** Pre-formatted issue date, e.g. "Jun 25, 2026". */
issueDate: string;
/** Account holder's email; the signature line shows a name derived from it. */
holderEmail?: string | null;
/** Display currency; drives the glyph, amount-in-words, and currency picker. */
currency: "ILS" | "USD" | "EUR";
/** Finalized recipient shown (linked) in review/success mode. */
payee: string;
/** Controlled recipient email (form mode). */
recipientEmail: string;
/** Controlled amount string (drives the figure + amount-in-words). */
amount: string;
/** Controlled memo (form) / static memo (review, success). */
reason: string;
errors?: { recipientEmail?: string; amount?: string; reason?: string };
onRecipientEmailChange?: (value: string) => void;
onAmountChange?: (value: string) => void;
onReasonChange?: (value: string) => void;
onCurrencyChange?: (currency: "ILS" | "USD" | "EUR") => void;

dtsPropsFor.NotFoundSlip:
/** The dead path, shown on the "Requested" ledger line. */
requested: string;
/** Pre-formatted print timestamp, e.g. "2026-06-25 14:32". */
printedAt: string;
/** Deterministic "declined" reference number, e.g. "VRL-7F3A2C". */
reference: string;

dtsPropsFor.TransactionList:
