page?: number;
onPageChange?: (page: number) => void;
/** Denser row layout. */
compact?: boolean;
/** Makes rows selectable and fires with the chosen transaction. */
onTransactionSelect?: (transaction: { id: string; amount: number; counterpartyEmail: string }) => void;

dtsPropsFor.TransactionReceipt:
